import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import './AICoach.css';

// Elite-focused activities
const allTasks = {
  focus: [
    { id: 1, activity: 'Deep Work Protocol', description: '90-minute distraction-free focused sessions with neurofeedback', duration: '90 min', icon: '🚀', energyImpact: '+42%' },
    { id: 2, activity: 'Cognitive Priming', description: 'Prepare neural pathways for peak problem-solving', duration: '15 min', icon: '🧠', energyImpact: '+27%' },
  ],
  decision: [
    { id: 3, activity: 'Strategic Clarity Session', description: 'Enhance decision-making under uncertainty', duration: '20 min', icon: '🎯', energyImpact: '+35%' },
    { id: 4, activity: 'First-Principles Thinking', description: 'Break down complex problems to fundamental truths', duration: '25 min', icon: '🔍', energyImpact: '+38%' },
  ],
  recovery: [
    { id: 5, activity: 'Biohacking Recovery', description: 'Optimize cellular regeneration with guided protocols', duration: '30 min', icon: '⚡', energyImpact: '+51%' },
    { id: 6, activity: 'Neural Reset', description: 'Pattern interruption for creative breakthrough', duration: '18 min', icon: '🔄', energyImpact: '+33%' },
  ]
};

function AICoach({ user }) {
  const [dailyPlan, setDailyPlan] = useState([]);
  const [activeTab, setActiveTab] = useState('Morning');

  useEffect(() => {
    // Generate static engaging daily plan
    const plan = [
      ...allTasks.focus,
      ...allTasks.decision,
      ...allTasks.recovery
    ].map((t, index) => ({
      ...t,
      completed: index === 0,
      scheduledTime: index < 2 ? 'Morning' : index < 4 ? 'Afternoon' : 'Evening',
      optimalTime: `${Math.floor(Math.random() * 4) + 8}:00 AM`
    }));
    setDailyPlan(plan);
  }, []);

  const handleToggle = (id) => {
    setDailyPlan(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const completedCount = dailyPlan.filter(t => t.completed).length;
  const totalCount = dailyPlan.length;
  const progressPercent = totalCount > 0 ? (completedCount / totalCount) * 100 : 0;
  const dashOffset = 283 - ((progressPercent / 100) * 283);

  return (
    <div className="ai-tab-wrapper">
      <div className="ai-dashboard-header">
        <div className="coach-identity">
          <div className="coach-avatar-lg">
            <span>✨</span>
          </div>
          <div>
            <h1>MindSync Neuro-Coach</h1>
            <p>Adaptive Cognitive Optimization</p>
          </div>
        </div>
      </div>

      <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="coach-msg-card">
        <p>
          "I've analyzed your biometric patterns from yesterday. Your neural recovery is optimal, meaning today is ideal for high-impact deep work and strategic decision making."
        </p>
      </motion.div>

      <div className="ai-grid">
        {/* Progress Tracker */}
        <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: 0.1 }} className="ai-card">
          <h3>📊 Today's Optimization Protocol</h3>
          <div className="progress-visual">
            <div className="progress-circle">
              <svg viewBox="0 0 100 100">
                <defs>
                  <linearGradient id="gradient" x1="0%" y1="0%" x2="100%" y2="0%">
                    <stop offset="0%" stopColor="#6366f1" />
                    <stop offset="100%" stopColor="#ec4899" />
                  </linearGradient>
                </defs>
                <circle className="progress-background" cx="50" cy="50" r="45" />
                <circle 
                  className="progress-fill" 
                  cx="50" cy="50" r="45" 
                  strokeDasharray="283" 
                  strokeDashoffset={dashOffset} 
                />
              </svg>
              <div className="progress-text">
                <span className="percentage">{Math.round(progressPercent)}%</span>
                <span className="label">Complete</span>
              </div>
            </div>

            <div className="progress-stats">
              <div className="stat-box">
                <span className="value">{completedCount}</span>
                <span className="label">Done</span>
              </div>
              <div className="stat-box">
                <span className="value">{totalCount - completedCount}</span>
                <span className="label">Remaining</span>
              </div>
            </div>
          </div>
        </motion.div>

        {/* AI Insights Base */}
        <motion.div initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: 0.2 }} className="ai-card">
          <h3>🧠 Neural Insights</h3>
          <div className="insight-item">
            <p>Your cognitive performance peaks between 10:00-12:30. Schedule critical decisions during this window.</p>
          </div>
          <div className="rec-list">
            <div className="rec-item">💡 Decision fatigue reduces by 44% when you make critical choices before 1 PM.</div>
            <div className="rec-item">💡 Your focus endurance increases by 27% when preceded by 7 minutes of box breathing.</div>
          </div>
        </motion.div>
      </div>

      {/* Plan Details */}
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 }} className="ai-card" style={{ padding: '40px' }}>
        <h3>🎯 Task Matrix</h3>

        <div className="time-tabs">
          {['Morning', 'Afternoon', 'Evening'].map(time => (
            <button key={time} className={`time-tab ${activeTab === time ? 'active' : ''}`} onClick={() => setActiveTab(time)}>
              {time}
            </button>
          ))}
        </div>

        <div className="coach-plan">
          <AnimatePresence mode="popLayout">
            {dailyPlan.filter(t => t.scheduledTime === activeTab).map((item, i) => (
              <motion.div 
                key={item.id} 
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                className={`coach-item ${item.completed ? 'completed' : ''}`}
              >
                <div className="task-timing">
                  <span className="scheduled-time">{item.scheduledTime}</span>
                  <span className="optimal-time">Peak: {item.optimalTime}</span>
                </div>
                <div className="task-icon">{item.icon}</div>
                <div className="task-details">
                  <h4>{item.activity}</h4>
                  <p>{item.description}</p>
                  <div className="task-tags">
                    <span className="task-tag tag-duration">⏳ {item.duration}</span>
                    <span className="task-tag tag-impact">🔋 {item.energyImpact} Boost</span>
                  </div>
                </div>
                <motion.button
                  whileTap={{ scale: 0.9 }}
                  className={`task-action ${item.completed ? 'done' : 'start'}`}
                  onClick={() => handleToggle(item.id)}
                >
                  {item.completed ? 'Completed ✓' : 'Start Task'}
                </motion.button>
              </motion.div>
            ))}
          </AnimatePresence>
          {dailyPlan.filter(t => t.scheduledTime === activeTab).length === 0 && (
            <div style={{ padding: '30px', textAlign: 'center', color: '#64748b' }}>No tasks scheduled for this block.</div>
          )}
        </div>
      </motion.div>
    </div>
  );
}

export default AICoach;
